import React from 'react';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
import { FaExternalLinkAlt, FaGithub } from 'react-icons/fa';
import './Projects.css';

const Projects = () => {
  const [ref, inView] = useInView({
    triggerOnce: true,
    threshold: 0.1
  });

  const projects = [
    {
      title: 'Direct Property',
      description: 'Built a property management system to handle listings, ownership, and transactions. Designed efficient backend logic for data management and workflow automation.',
      tech: ['MongoDB', 'Express', 'React', 'Node.js'],
      category: 'Full Stack'
    },
    {
      title: 'Student Performance Tracker',
      description: 'Developed a machine learning model to analyze and predict student performance. Performed data preprocessing, visualization, and model training.',
      tech: ['Python', 'Streamlit', 'ML'],
      category: 'Machine Learning'
    },
    {
      title: 'Data Guarding',
      description: 'Developed a secure agricultural data management system to replace manual record-keeping. Improved data integrity, automation, and workflow efficiency.',
      tech: ['Next.js', 'React'],
      category: 'Web Application'
    },
    {
      title: 'Data Securer',
      description: 'Designed a system to ensure secure storage and protection of sensitive data. Implemented data integrity checks and basic encryption techniques.',
      tech: ['MERN Stack', 'Blockchain'],
      category: 'Security'
    },
    {
      title: 'Recipe Bot',
      description: 'Built an ingredient-based recipe recommendation system with a user-friendly interface. Implemented personalized suggestions using efficient dataset handling.',
      tech: ['HTML', 'CSS', 'JavaScript'],
      category: 'Web Application'
    }
  ];

  return (
    <section className="projects" id="projects">
      <div className="container">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 50 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <h2 className="section-title">Featured Projects</h2>

          <div className="projects-grid">
            {projects.map((project, index) => (
              <motion.div
                key={index}
                className="project-card"
                initial={{ opacity: 0, y: 30 }}
                animate={inView ? { opacity: 1, y: 0 } : {}}
                transition={{ delay: index * 0.15, duration: 0.5 }}
                whileHover={{ y: -10 }}
              >
                <div className="project-category-badge">{project.category}</div>
                
                <h3>{project.title}</h3>
                <p className="project-description">{project.description}</p>

                <div className="project-tech">
                  {project.tech.map((tech, idx) => (
                    <span key={idx} className="tech-tag">{tech}</span>
                  ))}
                </div>

                <div className="project-links">
                  <a href="#" className="project-link">
                    <FaExternalLinkAlt /> Live Demo
                  </a>
                  <a href="#" className="project-link">
                    <FaGithub /> Source Code
                  </a>
                </div>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default Projects;
